import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Group, Button, Text, Image, ActionIcon, Box, Transition } from '@mantine/core';
import { X, ArrowRight } from 'lucide-react';
import { useAppStore } from '../../store/useAppStore';
import { useVehicleStore } from '../../store/useVehicleStore';

export default function CompareBar() {
    const compareList = useAppStore((s) => s.compareList);
    const removeFromCompare = useAppStore((s) => s.removeFromCompare);
    const clearCompare = useAppStore((s) => s.clearCompare);
    const getVehicleById = useVehicleStore((s) => s.getVehicleById);
    const navigate = useNavigate();

    const vehicles = compareList.map((id) => getVehicleById(id)).filter(Boolean);

    return (
        <Transition mounted={compareList.length > 0} transition="slide-up" duration={280}>
            {(styles) => (
                <Box
                    style={{
                        ...styles,
                        position: 'fixed',
                        bottom: 0, left: 0, right: 0,
                        background: 'rgba(20,21,23,0.97)',
                        backdropFilter: 'blur(20px)',
                        WebkitBackdropFilter: 'blur(20px)',
                        borderTop: '1px solid rgba(0,200,117,0.25)',
                        zIndex: 500,
                        boxShadow: '0 -8px 40px rgba(0,0,0,0.6)',
                        padding: '12px 32px',
                    }}
                >
                    <Group justify="space-between" align="center" maw={1440} mx="auto">
                        {/* Slots */}
                        <Group gap="md">
                            {[0, 1].map((slot) => {
                                const v = vehicles[slot];
                                return (
                                    <Box
                                        key={slot}
                                        style={{
                                            display: 'flex', alignItems: 'center', gap: 10,
                                            padding: '8px 14px',
                                            background: v ? 'rgba(255,255,255,0.05)' : 'rgba(255,255,255,0.02)',
                                            border: `1px solid ${v ? 'rgba(0,200,117,0.25)' : 'rgba(255,255,255,0.07)'}`,
                                            borderRadius: 10,
                                            minWidth: 180,
                                            height: 52,
                                        }}
                                    >
                                        {v ? (
                                            <>
                                                <Box
                                                    style={{
                                                        width: 36, height: 36, borderRadius: 6,
                                                        backgroundColor: v.thumbnailColor,
                                                        overflow: 'hidden', flexShrink: 0,
                                                    }}
                                                >
                                                    <img
                                                        src={v.image} alt=""
                                                        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                                        onError={(e) => { e.target.style.display = 'none'; }}
                                                    />
                                                </Box>
                                                <Box style={{ flex: 1 }}>
                                                    <Text fz={13} fw={600} c="white" lh={1.2}>{v.make} {v.model}</Text>
                                                    <Text fz={11} c="dimmed">{v.year}</Text>
                                                </Box>
                                                <ActionIcon
                                                    size="sm" variant="subtle" color="gray"
                                                    onClick={() => removeFromCompare(v.id)}
                                                    aria-label={`Remove ${v.make}`}
                                                >
                                                    <X size={13} />
                                                </ActionIcon>
                                            </>
                                        ) : (
                                            <Text fz={12} c="dimmed" style={{ fontStyle: 'italic' }}>
                                                {slot === 0 ? 'Select first vehicle' : 'Select second vehicle'}
                                            </Text>
                                        )}
                                    </Box>
                                );
                            })}
                        </Group>

                        {/* Actions */}
                        <Group gap="sm">
                            {compareList.length === 2 && (
                                <Button
                                    color="brand"
                                    radius="md"
                                    rightSection={<ArrowRight size={14} />}
                                    fw={700}
                                    onClick={() => navigate('/compare')}
                                >
                                    Compare Now
                                </Button>
                            )}
                            <Button
                                variant="subtle"
                                color="gray"
                                size="sm"
                                onClick={clearCompare}
                            >
                                Clear All
                            </Button>
                        </Group>
                    </Group>
                </Box>
            )}
        </Transition>
    );
}

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
    Group, Button, Text, ActionIcon, Badge, Box, Drawer, Stack, Divider,
} from '@mantine/core';
import { useDisclosure, useWindowScroll } from '@mantine/hooks';
import { Plus, Menu, X, GitCompare, Home, Zap, UserCircle } from 'lucide-react';
import { useAppStore } from '../../store/useAppStore';
import { useAuthStore } from '../../store/useAuthStore';

export default function Navbar() {
    const navigate = useNavigate();
    const location = useLocation();
    const compareList = useAppStore((s) => s.compareList);
    const user = useAuthStore((s) => s.user);
    const [drawerOpened, { open: openDrawer, close: closeDrawer }] = useDisclosure(false);
    const [scroll] = useWindowScroll();

    const navTo = (path) => { navigate(path); closeDrawer(); };
    const isScrolled = scroll.y > 20;

    return (
        <>
            {/* ── Futuristic Floating Navbar ── */}
            <Box
                style={{
                    position: 'fixed',
                    top: isScrolled ? 12 : 16,
                    left: '50%',
                    transform: 'translateX(-50%)',
                    zIndex: 1000,
                    width: '90%',
                    maxWidth: 1200,
                    height: 64,
                    background: isScrolled ? 'rgba(13, 17, 23, 0.85)' : 'rgba(13, 17, 23, 0.65)',
                    backdropFilter: 'blur(16px)',
                    WebkitBackdropFilter: 'blur(16px)',
                    border: '1px solid rgba(59, 130, 246, 0.2)',
                    borderRadius: 999,
                    padding: '0 20px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                    boxShadow: isScrolled
                        ? '0 10px 40px rgba(0, 0, 0, 0.8), 0 0 0 1px rgba(59, 130, 246, 0.15)'
                        : '0 4px 24px rgba(0, 0, 0, 0.4)',
                }}
            >
                {/* Glow behind nav */}
                <Box style={{
                    position: 'absolute', inset: -1, borderRadius: 999, zIndex: -1,
                    background: 'linear-gradient(90deg, transparent, rgba(59,130,246,0.1), transparent)',
                    opacity: isScrolled ? 1 : 0.5, transition: 'opacity 0.4s',
                }} />

                {/* ── Logo ── */}
                <Group gap={8} style={{ cursor: 'pointer', userSelect: 'none' }} onClick={() => navTo('/')}>
                    <img src="/favicon.svg" alt="AutoGenesis" style={{ height: 24, width: 'auto' }} />
                    <Text ff="var(--font-display)" fz={22} lts="0.08em" style={{ color: '#fff', lineHeight: 1 }}>
                        AUTO<span style={{ color: '#3b82f6' }}>GENESIS</span>
                    </Text>
                </Group>

                {/* ── Center Links (Desktop) ── */}
                <Group gap={24} visibleFrom="md">
                    <NavLink label="Fleet" path="/" active={location.pathname === '/'} onClick={() => navTo('/')} />
                    <NavLink
                        label="Compare"
                        path="/compare"
                        active={location.pathname === '/compare'}
                        onClick={() => navTo('/compare')}
                        badge={compareList.length > 0 ? compareList.length : null}
                    />
                </Group>

                {/* ── Right Actions ── */}
                <Group gap="sm">
                    {/* Neon Add Button (Desktop) */}
                    {user ? (
                        <>
                            <Button
                                visibleFrom="md"
                                radius="xl"
                                size="sm"
                                leftSection={<Plus size={14} strokeWidth={3} />}
                                onClick={() => navTo('/add-vehicle')}
                                style={{
                                    background: 'transparent',
                                    border: '1px solid #3b82f6',
                                    color: '#3b82f6',
                                    fontWeight: 700,
                                    boxShadow: 'inset 0 0 12px rgba(59,130,246,0.2), 0 0 12px rgba(59,130,246,0.2)',
                                    transition: 'all 0.3s ease',
                                }}
                                styles={{
                                    root: { '&:hover': { background: '#3b82f6', color: '#fff', boxShadow: '0 0 24px rgba(59,130,246,0.6)' } }
                                }}
                            >
                                Add Vehicle
                            </Button>
                            <Button
                                visibleFrom="md"
                                variant="subtle"
                                onClick={() => navTo('/profile')}
                                style={{ color: 'white', padding: '0 8px' }}
                            >
                                <Group gap={8}>
                                    <UserCircle size={20} />
                                    <Text fw={600} fz="sm">{user.name.split(' ')[0]}</Text>
                                </Group>
                            </Button>
                        </>
                    ) : (
                        <Button
                            visibleFrom="md"
                            radius="xl"
                            size="sm"
                            onClick={() => navTo('/login')}
                            style={{
                                background: '#3b82f6',
                                color: '#fff',
                                fontWeight: 700,
                                boxShadow: '0 4px 15px rgba(59, 130, 246, 0.4)'
                            }}
                        >
                            Login / Sign Up
                        </Button>
                    )}

                    {/* Mobile Hamburger */}
                    <ActionIcon
                        hiddenFrom="md"
                        variant="subtle"
                        color="brand"
                        size="lg"
                        radius="xl"
                        onClick={openDrawer}
                        style={{ background: 'rgba(59,130,246,0.1)' }}
                    >
                        <Menu size={18} />
                    </ActionIcon>
                </Group>
            </Box>

            {/* ── Mobile Drawer ── */}
            <Drawer
                opened={drawerOpened}
                onClose={closeDrawer}
                position="right"
                size="280px"
                zIndex={2000}
                withCloseButton={false}
                styles={{
                    body: { padding: 0 },
                    content: { background: '#080c12', borderLeft: '1px solid rgba(59,130,246,0.2)' },
                    overlay: { backdropFilter: 'blur(8px)', background: 'rgba(0,0,0,0.6)' },
                }}
            >
                <Group justify="space-between" p="md" style={{ borderBottom: '1px solid rgba(255,255,255,0.04)' }}>
                    <Group gap={8}>
                        <img src="/favicon.svg" alt="AutoGenesis" style={{ height: 20 }} />
                        <Text ff="var(--font-display)" fz={18} c="white" lts="0.05em">AUTO<span style={{ color: '#3b82f6' }}>GENESIS</span></Text>
                    </Group>
                    <ActionIcon variant="subtle" color="gray" onClick={closeDrawer}><X size={18} /></ActionIcon>
                </Group>

                <Stack gap={0} p="md">
                    <DrawerNavItem icon={<Home size={16} />} label="Fleet" active={location.pathname === '/'} onClick={() => navTo('/')} />
                    <DrawerNavItem
                        icon={<GitCompare size={16} />} label="Compare"
                        active={location.pathname === '/compare'}
                        badge={compareList.length > 0 ? compareList.length : null}
                        onClick={() => navTo('/compare')}
                    />
                    <Divider my="md" color="rgba(255,255,255,0.06)" />
                    {user ? (
                        <>
                            <Button
                                leftSection={<Plus size={14} />}
                                color="brand" radius="md" fullWidth fw={700} mb="sm"
                                onClick={() => navTo('/add-vehicle')}
                                style={{ boxShadow: '0 4px 16px rgba(59,130,246,0.4)' }}
                            >
                                Add Vehicle
                            </Button>
                            <Button
                                leftSection={<UserCircle size={14} />}
                                variant="outline" color="brand" radius="md" fullWidth fw={700}
                                onClick={() => navTo('/profile')}
                            >
                                My Profile
                            </Button>
                        </>
                    ) : (
                        <Button
                            color="brand" radius="md" fullWidth fw={700}
                            onClick={() => navTo('/login')}
                            style={{ boxShadow: '0 4px 16px rgba(59,130,246,0.4)' }}
                        >
                            Login / Sign Up
                        </Button>
                    )}
                </Stack>
            </Drawer>

            {/* Spacer to push content down since navbar is fixed */}
            <Box h={isScrolled ? 50 : 80} style={{ transition: 'height 0.4s' }} />
        </>
    );
}

function NavLink({ label, active, onClick, badge }) {
    return (
        <Button
            variant="subtle"
            onClick={onClick}
            style={{
                position: 'relative',
                color: active ? '#fff' : 'rgba(255,255,255,0.6)',
                fontWeight: 600,
                fontSize: 14,
                fontFamily: 'var(--font-body)',
            }}
            styles={{
                root: {
                    '&:hover': {
                        color: '#fff',
                        background: 'rgba(255,255,255,0.05)',
                        transform: 'translateY(-1px)',
                    },
                    transition: 'all 0.2s ease',
                }
            }}
        >
            <Group gap={8}>
                {label}
                {badge && <Badge size="xs" color="brand" variant="filled" circle>{badge}</Badge>}
            </Group>
            {active && (
                <Box style={{
                    position: 'absolute', bottom: 4, left: 16, right: 16, height: 2,
                    background: '#3b82f6', borderRadius: 2,
                    boxShadow: '0 -2px 8px rgba(59,130,246,0.8)'
                }} />
            )}
        </Button>
    );
}

function DrawerNavItem({ icon, label, badge, active, onClick }) {
    return (
        <Button
            variant={active ? 'light' : 'subtle'}
            color={active ? 'brand' : 'gray'}
            fullWidth radius="md"
            leftSection={icon}
            justify="flex-start"
            style={{ fontWeight: 600, fontSize: 15, paddingLeft: 12, marginBottom: 4 }}
            onClick={onClick}
        >
            <Group justify="space-between" w="100%">
                <span>{label}</span>
                {badge && <Badge size="sm" color="brand" variant="filled" circle>{badge}</Badge>}
            </Group>
        </Button>
    );
}

import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm, zodResolver } from '@mantine/form';
import {
    Container, Stepper, Button, Group, Stack, Text, Box,
    TextInput, NumberInput, Select, Textarea, Switch, Paper,
    ColorInput, FileInput, SimpleGrid, ActionIcon, Badge,
    SegmentedControl, Divider, Alert,
} from '@mantine/core';
import {
    ChevronRight, ChevronLeft, Plus, Minus, Send,
    Car, Cpu, Activity, Award, Clock, BookOpen, AlertCircle,
} from 'lucide-react';
import { step1Schema, step2Schema, step3Schema, step4Schema } from './schema/validation';
import { useVehicleStore } from '../../store/useVehicleStore';
import { useAppStore } from '../../store/useAppStore';
import { saveVehicle, saveVehicleImage } from '../../utils/vehicleStorage';
import { PHASE_COLORS } from '../../data/phaseColors';
import '../../styles/AddVehicle.css';

const STEPS = [
    { label: 'Basic Info', icon: <Car size={14} /> },
    { label: 'Tech Specs', icon: <Cpu size={14} /> },
    { label: 'Condition', icon: <Activity size={14} /> },
    { label: 'Badges', icon: <Award size={14} /> },
    { label: 'Timeline', icon: <Clock size={14} /> },
    { label: 'Review', icon: <BookOpen size={14} /> },
];

const STEP_SCHEMAS = [step1Schema, step2Schema, step3Schema, step4Schema];

function defaultTimeline() {
    return [{
        id: Date.now(),
        phase: 'manufacture', source: '', date: '', title: '', detail: '', verified: false,
    }];
}

export default function AddVehicle() {
    const navigate = useNavigate();
    const showToast = useAppStore((s) => s.showToast);
    const refreshVehicles = useVehicleStore((s) => s.refreshCustomVehicles);

    const [active, setActive] = useState(0);
    const [imageFile, setImageFile] = useState(null);
    const [imagePreview, setImagePreview] = useState('');
    const [timeline, setTimeline] = useState(defaultTimeline());
    const [submitting, setSubmitting] = useState(false);

    /* ── Mantine form with Zod resolver — per-step validation ── */
    const form = useForm({
        mode: 'controlled',
        initialValues: {
            // Step 1
            make: '', model: '', variant: '', year: new Date().getFullYear(),
            colorName: '', colorHex: '#888888',
            // Step 2
            vin: '', engineNo: '', fuelType: '', displacement: '',
            transmission: '', driveType: '', bodyType: '', doors: 4, seats: 5,
            // Step 3
            condition_grade: 4, mileage: 0, market_value_lkr: 0,
            // Step 4
            on_time_service: false, one_owner: false, no_accident: false, untampered_mileage: false,
        },
        validate: zodResolver(
            active === 0 ? step1Schema :
                active === 1 ? step2Schema :
                    active === 2 ? step3Schema :
                        active === 3 ? step4Schema : undefined
        ),
    });

    /* ── Step navigation ── */
    const nextStep = () => {
        if (active < 4) {
            const res = form.validate();
            if (res.hasErrors) return;
        }
        setActive((s) => Math.min(s + 1, STEPS.length - 1));
    };

    const prevStep = () => setActive((s) => Math.max(s - 1, 0));

    /* ── Image ── */
    const handleImageChange = useCallback((file) => {
        setImageFile(file);
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => setImagePreview(e.target.result);
            reader.readAsDataURL(file);
        } else {
            setImagePreview('');
        }
    }, []);

    /* ── Timeline helpers ── */
    const addEvent = () => setTimeline((prev) => [
        ...prev,
        { id: Date.now(), phase: 'service', source: '', date: '', title: '', detail: '', verified: false },
    ]);
    const removeEvent = (id) => setTimeline((prev) => prev.filter((e) => e.id !== id));
    const updateEvent = (id, field, value) =>
        setTimeline((prev) => prev.map((e) => e.id === id ? { ...e, [field]: value } : e));

    /* ── Submit ── */
    const handleSubmit = async () => {
        setSubmitting(true);
        try {
            const vals = form.getValues();
            const id = `AG-CUSTOM-${Date.now()}`;
            const vehicle = {
                id,
                make: vals.make,
                model: vals.model,
                variant: vals.variant,
                year: vals.year,
                color: vals.colorName,
                colorHex: vals.colorHex,
                vin: vals.vin,
                chassisNo: vals.vin,
                engineNo: vals.engineNo,
                fuelType: vals.fuelType,
                displacement: vals.displacement,
                transmission: vals.transmission,
                driveType: vals.driveType,
                bodyType: vals.bodyType,
                doors: vals.doors,
                seats: vals.seats,
                age: new Date().getFullYear() - vals.year,
                mileage: vals.mileage,
                condition_grade: vals.condition_grade,
                condition_label: ['', 'Poor', 'Below Average', 'Fair', 'Good', 'Excellent'][vals.condition_grade] || 'Good',
                market_value_lkr: vals.market_value_lkr,
                thumbnailColor: vals.colorHex,
                image: imagePreview ? '__ls__' : '',
                badges: {
                    on_time_service: vals.on_time_service,
                    one_owner: vals.one_owner,
                    no_accident: vals.no_accident,
                    untampered_mileage: vals.untampered_mileage,
                },
                depreciation: [{ year: vals.year, value: vals.market_value_lkr }],
                timeline: timeline.map(({ id: _id, ...rest }) => ({ ...rest, verified: rest.verified || false })),
                isCustom: true,
            };

            saveVehicle(vehicle);
            if (imagePreview) saveVehicleImage(id, imagePreview);
            refreshVehicles();
            showToast(`${vehicle.make} ${vehicle.model} added to your fleet!`, 'success');
            navigate('/');
        } catch (err) {
            showToast('Failed to save vehicle. Please try again.', 'error');
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <Container size="md" py="xl">
            {/* Header */}
            <Button variant="subtle" color="gray" leftSection={<ChevronLeft size={14} />}
                onClick={() => navigate('/')} mb="lg">
                Back to Gallery
            </Button>
            <Text ff="var(--font-display)" fz={40} c="white" lts="0.04em" mb={4}>ADD NEW VEHICLE</Text>
            <Text c="dimmed" fz={14} mb="xl">Complete all 6 steps to create a full vehicle passport record.</Text>

            {/* Stepper */}
            <Stepper active={active} onStepClick={setActive} size="sm" mb="xl" allowNextStepsSelect={false}>
                {STEPS.map((step) => (
                    <Stepper.Step key={step.label} label={step.label} icon={step.icon} />
                ))}
            </Stepper>

            {/* Content panel */}
            <Paper radius="xl" p="xl" style={{ border: '1px solid rgba(255,255,255,0.07)' }}>
                {/* ── Step 0: Basic Info ── */}
                {active === 0 && (
                    <Stack gap="lg">
                        <StepHeader title="Basic Information" desc="Start with the vehicle's core identity details." />
                        <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="md">
                            <TextInput label="Make" placeholder="e.g. Toyota" required {...form.getInputProps('make')} />
                            <TextInput label="Model" placeholder="e.g. Aqua" required {...form.getInputProps('model')} />
                            <TextInput label="Variant / Trim" placeholder="e.g. G Grade" {...form.getInputProps('variant')} />
                            <NumberInput label="Year" required min={1900} max={new Date().getFullYear() + 1} {...form.getInputProps('year')} />
                            <TextInput label="Color Name" placeholder="e.g. Pearl White" required {...form.getInputProps('colorName')} />
                            <ColorInput label="Color Hex Code" format="hex" {...form.getInputProps('colorHex')} />
                        </SimpleGrid>
                        <Divider label="Vehicle Photo" labelPosition="left" />
                        <FileInput
                            label="Upload Photo (JPG, PNG, WebP · max 5 MB)"
                            placeholder="Click to upload..."
                            accept="image/*"
                            value={imageFile}
                            onChange={handleImageChange}
                            radius="md"
                        />
                        {imagePreview && (
                            <Box style={{ borderRadius: 10, overflow: 'hidden', maxHeight: 200 }}>
                                <img src={imagePreview} alt="preview" style={{ width: '100%', objectFit: 'cover' }} />
                            </Box>
                        )}
                    </Stack>
                )}

                {/* ── Step 1: Tech Specs ── */}
                {active === 1 && (
                    <Stack gap="lg">
                        <StepHeader title="Technical Specifications" desc="Enter the vehicle's mechanical and registration details." />
                        <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="md">
                            <TextInput label="VIN / Chassis Number" placeholder="e.g. NHP10-1234567" required {...form.getInputProps('vin')} />
                            <TextInput label="Engine Number" placeholder="e.g. 1NZ-B456789" required {...form.getInputProps('engineNo')} />
                            <Select
                                label="Fuel Type" placeholder="Select fuel type" required
                                data={['Hybrid', 'Electric', 'Plug-in Hybrid', 'Petrol', 'Diesel', 'Mild Hybrid (SHVS)']}
                                {...form.getInputProps('fuelType')}
                            />
                            <TextInput label="Engine Displacement" placeholder="e.g. 1500cc or Electric — 217hp" {...form.getInputProps('displacement')} />
                            <TextInput label="Transmission" placeholder="e.g. CVT, 7-Speed DCT, Auto" required {...form.getInputProps('transmission')} />
                            <Select
                                label="Drive Type" placeholder="Select drive type" required
                                data={['FWD', 'RWD', 'AWD', '4WD']}
                                {...form.getInputProps('driveType')}
                            />
                            <Select
                                label="Body Type" placeholder="Select body type" required
                                data={['Sedan', 'Hatchback', 'SUV', 'Crossover SUV', 'MPV', 'Wagon', 'Van', 'Pickup', 'Kei Car / Mini MPV', 'Coupe', 'Convertible']}
                                {...form.getInputProps('bodyType')}
                            />
                            <NumberInput label="Doors" min={2} max={8} {...form.getInputProps('doors')} />
                            <NumberInput label="Seats" min={1} max={15} {...form.getInputProps('seats')} />
                        </SimpleGrid>
                    </Stack>
                )}

                {/* ── Step 2: Condition ── */}
                {active === 2 && (
                    <Stack gap="lg">
                        <StepHeader title="Condition & Value" desc="Describe the vehicle's current condition and market value." />
                        <Box>
                            <Text fz={12} fw={600} tt="uppercase" lts="0.06em" c="dimmed" mb="sm">Condition Grade *</Text>
                            <Group gap="sm">
                                {[1, 2, 3, 4, 5].map((g) => {
                                    const colors = { 1: '#FF4545', 2: '#FF8C42', 3: '#F5C842', 4: '#00C875', 5: '#4A9EFF' };
                                    const labels = { 1: 'Poor', 2: 'Below Avg', 3: 'Fair', 4: 'Good', 5: 'Excellent' };
                                    const selected = form.getValues().condition_grade === g;
                                    return (
                                        <Button
                                            key={g}
                                            variant={selected ? 'filled' : 'outline'}
                                            style={{
                                                borderColor: colors[g],
                                                background: selected ? colors[g] : 'transparent',
                                                color: selected ? '#000' : colors[g],
                                                fontWeight: 700,
                                                minWidth: 72,
                                            }}
                                            onClick={() => form.setFieldValue('condition_grade', g)}
                                        >
                                            {g}★ {labels[g]}
                                        </Button>
                                    );
                                })}
                            </Group>
                        </Box>
                        <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="md">
                            <NumberInput label="Mileage (km)" required min={0} max={1000000} step={1000} {...form.getInputProps('mileage')} />
                            <NumberInput label="Market Value (LKR)" required min={1} step={100000} {...form.getInputProps('market_value_lkr')} />
                        </SimpleGrid>
                    </Stack>
                )}

                {/* ── Step 3: Badges ── */}
                {active === 3 && (
                    <Stack gap="lg">
                        <StepHeader title="Trust Badges" desc="Toggle the badges this vehicle has earned." />
                        <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="md">
                            {[
                                { key: 'on_time_service', label: 'On-Time Service', desc: 'All services done on schedule' },
                                { key: 'one_owner', label: 'Single Owner', desc: 'Only one previous owner' },
                                { key: 'no_accident', label: 'No Accident', desc: 'No recorded accidents' },
                                { key: 'untampered_mileage', label: 'Mileage Verified', desc: 'Odometer not tampered' },
                            ].map(({ key, label, desc }) => (
                                <Paper
                                    key={key} p="md" radius="md"
                                    style={{
                                        border: form.getValues()[key] ? '1px solid rgba(0,200,117,0.3)' : '1px solid rgba(255,255,255,0.07)',
                                        background: form.getValues()[key] ? 'rgba(0,200,117,0.05)' : '#1A1B1E',
                                        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                                    }}
                                >
                                    <Stack gap={2}>
                                        <Text fz={14} fw={600} c="white">{label}</Text>
                                        <Text fz={12} c="dimmed">{desc}</Text>
                                    </Stack>
                                    <Switch
                                        checked={form.getValues()[key]}
                                        onChange={(e) => form.setFieldValue(key, e.currentTarget.checked)}
                                        color="brand"
                                    />
                                </Paper>
                            ))}
                        </SimpleGrid>
                    </Stack>
                )}

                {/* ── Step 4: Timeline ── */}
                {active === 4 && (
                    <Stack gap="lg">
                        <Group justify="space-between">
                            <StepHeader title="Timeline Events" desc="Add key events in the vehicle's history." />
                            <Button
                                size="xs" variant="light" color="brand" leftSection={<Plus size={13} />}
                                onClick={addEvent}
                            >
                                Add Event
                            </Button>
                        </Group>

                        {timeline.length === 0 && (
                            <Alert icon={<AlertCircle size={14} />} color="gray" radius="md">
                                No events yet. Add at least one timeline event.
                            </Alert>
                        )}

                        <Stack gap="sm">
                            {timeline.map((ev, idx) => (
                                <Paper key={ev.id} radius="lg" style={{ border: '1px solid rgba(255,255,255,0.07)', overflow: 'hidden' }}>
                                    <Group p="sm" justify="space-between" style={{ background: '#111', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>
                                        <Text fz={13} fw={600} c="white">Event {idx + 1} — {ev.phase || 'No phase selected'}</Text>
                                        <ActionIcon size="sm" variant="subtle" color="red" onClick={() => removeEvent(ev.id)}><Minus size={12} /></ActionIcon>
                                    </Group>
                                    <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="md" p="md">
                                        <Select
                                            label="Phase"
                                            data={Object.entries(PHASE_COLORS).map(([k, v]) => ({ value: k, label: v.label }))}
                                            value={ev.phase}
                                            onChange={(val) => updateEvent(ev.id, 'phase', val)}
                                            required
                                        />
                                        <TextInput label="Source Name" placeholder="e.g. Toyota Motor Corporation"
                                            value={ev.source} onChange={(e) => updateEvent(ev.id, 'source', e.target.value)} required />
                                        <TextInput label="Date" type="date"
                                            value={ev.date} onChange={(e) => updateEvent(ev.id, 'date', e.target.value)} required />
                                        <TextInput label="Title/Summary" placeholder="e.g. Manufactured at Iwate Plant"
                                            value={ev.title} onChange={(e) => updateEvent(ev.id, 'title', e.target.value)} required />
                                        <Box style={{ gridColumn: '1 / -1' }}>
                                            <Textarea label="Detail" placeholder="Full event description..."
                                                value={ev.detail} onChange={(e) => updateEvent(ev.id, 'detail', e.target.value)}
                                                minRows={2} required />
                                        </Box>
                                        <Switch label="Verified by official source"
                                            checked={ev.verified}
                                            onChange={(e) => updateEvent(ev.id, 'verified', e.currentTarget.checked)}
                                            color="brand"
                                        />
                                    </SimpleGrid>
                                </Paper>
                            ))}
                        </Stack>
                    </Stack>
                )}

                {/* ── Step 5: Review ── */}
                {active === 5 && (
                    <Stack gap="xl">
                        <StepHeader title="Review & Submit" desc="Confirm all details before adding to your fleet." />
                        {(() => {
                            const v = form.getValues();
                            return (
                                <>
                                    {imagePreview && (
                                        <Box style={{ borderRadius: 12, overflow: 'hidden', maxHeight: 180 }}>
                                            <img src={imagePreview} alt="Vehicle" style={{ width: '100%', objectFit: 'cover' }} />
                                        </Box>
                                    )}
                                    <SimpleGrid cols={2} spacing="md">
                                        {[
                                            ['Make', v.make], ['Model', v.model], ['Year', v.year],
                                            ['Color', v.colorName], ['Fuel Type', v.fuelType], ['Transmission', v.transmission],
                                            ['Drive Type', v.driveType], ['Body Type', v.bodyType],
                                            ['Mileage', `${Number(v.mileage).toLocaleString()} km`],
                                            ['Market Value', `LKR ${Number(v.market_value_lkr).toLocaleString()}`],
                                            ['Condition Grade', `${v.condition_grade}/5`],
                                        ].map(([label, val]) => (
                                            <Box key={label}>
                                                <Text fz={10} c="dimmed" tt="uppercase" lts="0.06em">{label}</Text>
                                                <Text fz={14} fw={500} c="white">{val || '—'}</Text>
                                            </Box>
                                        ))}
                                    </SimpleGrid>
                                    <Divider />
                                    <Text fz={13} c="dimmed">{timeline.length} timeline event(s) added</Text>
                                    <Group gap="xs">
                                        {[['on_time_service', 'On-Time Service'], ['one_owner', 'One Owner'],
                                        ['no_accident', 'No Accident'], ['untampered_mileage', 'Mileage Verified']].map(([key, label]) => (
                                            <Badge key={key} variant={v[key] ? 'filled' : 'outline'} color={v[key] ? 'brand' : 'gray'} size="sm">
                                                {label}
                                            </Badge>
                                        ))}
                                    </Group>
                                </>
                            );
                        })()}
                    </Stack>
                )}
            </Paper>

            {/* Navigation */}
            <Group justify="space-between" mt="xl">
                <Button
                    variant="outline" color="gray" radius="md"
                    leftSection={<ChevronLeft size={14} />}
                    onClick={prevStep}
                    disabled={active === 0}
                >
                    Back
                </Button>
                <Text fz={13} c="dimmed">Step {active + 1} of {STEPS.length}</Text>
                {active < STEPS.length - 1 ? (
                    <Button
                        color="brand" radius="md" fw={700}
                        rightSection={<ChevronRight size={14} />}
                        onClick={nextStep}
                    >
                        Continue
                    </Button>
                ) : (
                    <Button
                        color="brand" radius="md" fw={700} size="md"
                        leftSection={<Send size={14} />}
                        onClick={handleSubmit}
                        loading={submitting}
                    >
                        Add to Fleet
                    </Button>
                )}
            </Group>
        </Container>
    );
}

function StepHeader({ title, desc }) {
    return (
        <Box mb="sm">
            <Text ff="var(--font-display)" fz={28} lts="0.04em" c="white">{title.toUpperCase()}</Text>
            <Text fz={13} c="dimmed">{desc}</Text>
            <Divider mt="sm" />
        </Box>
    );
}

import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    Box, Group, Stack, Text, Button, Badge, Container,
    Paper, SimpleGrid, Table, Divider, TextInput, Select,
} from '@mantine/core';
import { LineChart } from '@mantine/charts';
import { ArrowLeft, CheckCircle2, XCircle, Check, BookOpen, Search } from 'lucide-react';
import { useAppStore } from '../../store/useAppStore';
import { useVehicleStore } from '../../store/useVehicleStore';
import { formatLKR, formatKm, formatDate } from '../../utils/formatters';
import '../../styles/Compare.css';

function getAccidentCount(v) {
    return v.timeline?.filter((e) => e.phase === 'accident').length || 0;
}

function getWinner(key, v1, v2) {
    const higherIsBetter = ['year', 'condition_grade', 'market_value_lkr'];
    const lowerIsBetter = ['age', 'mileage'];
    const val1 = v1[key];
    const val2 = v2[key];
    if (val1 === val2 || (!val1 && !val2)) return 'tie';
    if (higherIsBetter.includes(key)) return val1 > val2 ? 'left' : 'right';
    if (lowerIsBetter.includes(key)) return val1 < val2 ? 'left' : 'right';
    return 'tie';
}

export default function Compare() {
    const navigate = useNavigate();
    const compareList = useAppStore((s) => s.compareList);
    const addToCompare = useAppStore((s) => s.addToCompare);
    const removeFromCompare = useAppStore((s) => s.removeFromCompare);
    const clearCompare = useAppStore((s) => s.clearCompare);
    const vehicles = useVehicleStore((s) => s.vehicles);
    const getVehicleById = useVehicleStore((s) => s.getVehicleById);

    const v1 = compareList[0] ? getVehicleById(compareList[0]) : null;
    const v2 = compareList[1] ? getVehicleById(compareList[1]) : null;

    /* ── Local filtering state ── */
    const [searchQuery, setSearchQuery] = useState('');
    const [fuelFilter, setFuelFilter] = useState('');
    const [gradeFilter, setGradeFilter] = useState('');

    const filteredVehicles = useMemo(() => {
        return vehicles.filter(v => {
            const matchesSearch = !searchQuery ||
                v.make.toLowerCase().includes(searchQuery.toLowerCase()) ||
                v.model.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesFuel = !fuelFilter || v.fuelType === fuelFilter;
            const matchesGrade = !gradeFilter || String(v.condition_grade) === gradeFilter;
            return matchesSearch && matchesFuel && matchesGrade;
        });
    }, [vehicles, searchQuery, fuelFilter, gradeFilter]);

    /* ── Empty state: let user pick ── */
    if (!v1 || !v2) {
        return (
            <Container size="lg" py="xl" style={{ marginTop: 80 }}>
                <Button variant="subtle" color="gray" leftSection={<ArrowLeft size={14} />}
                    onClick={() => navigate('/')} mb="lg">
                    Back to Gallery
                </Button>
                <Text ff="var(--font-display)" fz={36} c="white" mb={4}>Compare Vehicles</Text>
                <Text c="dimmed" mb="xl">Select two vehicles to compare side by side</Text>

                {/* Filters */}
                <Group mb="xl" style={{ background: 'rgba(255,255,255,0.02)', padding: 16, borderRadius: 12, border: '1px solid rgba(255,255,255,0.05)' }}>
                    <TextInput
                        placeholder="Search make or model..."
                        leftSection={<Search size={16} />}
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.currentTarget.value)}
                        style={{ flex: 1, minWidth: 200 }}
                    />
                    <Select
                        placeholder="All Fuels"
                        data={[
                            { value: '', label: 'All Fuels' },
                            { value: 'Petrol', label: 'Petrol' },
                            { value: 'Diesel', label: 'Diesel' },
                            { value: 'Hybrid', label: 'Hybrid' },
                            { value: 'Full Electric', label: 'Electric' }
                        ]}
                        value={fuelFilter}
                        onChange={setFuelFilter}
                    />
                    <Select
                        placeholder="All Grades"
                        data={[
                            { value: '', label: 'All Grades' },
                            { value: '5', label: 'Grade 5 (Excellent)' },
                            { value: '4', label: 'Grade 4 (Good)' },
                            { value: '3', label: 'Grade 3 (Fair)' },
                        ]}
                        value={gradeFilter}
                        onChange={setGradeFilter}
                    />
                </Group>

                <SimpleGrid cols={{ base: 2, sm: 3, md: 4 }} spacing="md">
                    {filteredVehicles.map((v) => {
                        const sel = compareList.includes(v.id);
                        return (
                            <Paper
                                key={v.id}
                                radius="lg" p="md"
                                style={{
                                    cursor: 'pointer',
                                    border: sel ? '1px solid rgba(0,200,117,0.5)' : '1px solid rgba(255,255,255,0.07)',
                                    background: sel ? 'rgba(0,200,117,0.06)' : '#1A1B1E',
                                    transition: 'all 0.2s',
                                }}
                                onClick={() => sel ? removeFromCompare(v.id) : addToCompare(v.id)}
                            >
                                <Box style={{ height: 70, overflow: 'hidden', borderRadius: 8, background: v.thumbnailColor, marginBottom: 10 }}>
                                    <img src={v.image} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                        onError={(e) => { e.target.style.display = 'none'; }} />
                                </Box>
                                <Text fz={13} fw={700} c="white">{v.make} {v.model}</Text>
                                <Text fz={11} c="dimmed">{v.year} · Grade {v.condition_grade}</Text>
                                {sel && <Badge size="xs" color="brand" mt={4}>Selected</Badge>}
                            </Paper>
                        );
                    })}
                </SimpleGrid>
            </Container>
        );
    }

    /* ── Comparison rows ── */
    const rows = [
        { label: 'Year', key: 'year', fmt: (v) => v.year },
        { label: 'Age', key: 'age', fmt: (v) => `${v.age} years` },
        { label: 'Mileage', key: 'mileage', fmt: (v) => formatKm(v.mileage) },
        { label: 'Condition Grade', key: 'condition_grade', fmt: (v) => `${v.condition_grade}/5 — ${v.condition_label}` },
        { label: 'Market Value', key: null, fmt: (v) => formatLKR(v.market_value_lkr) },
        { label: 'Fuel Type', key: null, fmt: (v) => v.fuelType },
        { label: 'Transmission', key: null, fmt: (v) => v.transmission },
        { label: 'Drive Type', key: null, fmt: (v) => v.driveType },
        { label: 'Displacement', key: null, fmt: (v) => v.displacement },
        { label: 'Accidents', key: null, accidents: true },
    ];

    /* ── Depreciation data for Mantine chart ── */
    const allYears = [...new Set([
        ...v1.depreciation.map((d) => d.year),
        ...v2.depreciation.map((d) => d.year),
    ])].sort();

    const depChartData = allYears.map((year) => ({
        year: String(year),
        [v1.make + ' ' + v1.model]: v1.depreciation.find((d) => d.year === year)?.value || null,
        [v2.make + ' ' + v2.model]: v2.depreciation.find((d) => d.year === year)?.value || null,
    }));

    const badgeKeys = ['on_time_service', 'one_owner', 'no_accident', 'untampered_mileage'];
    const badgeLabels = { on_time_service: 'On-Time Service', one_owner: 'One Owner', no_accident: 'No Accidents', untampered_mileage: 'Mileage Verified' };

    return (
        <Container size="lg" py="xl" style={{ marginTop: 80 }}>
            {/* Header */}
            <Group justify="space-between" mb="xl">
                <Group>
                    <Button variant="subtle" color="gray" leftSection={<ArrowLeft size={14} />} onClick={() => navigate('/')}>
                        Back
                    </Button>
                    <Text ff="var(--font-display)" fz={32} c="white">Compare Vehicles</Text>
                </Group>
                <Button variant="outline" color="gray" size="sm" onClick={clearCompare}>Change Vehicles</Button>
            </Group>

            {/* Vehicle heroes */}
            <SimpleGrid cols={2} spacing="md" mb="xl">
                {[v1, v2].map((v) => (
                    <Paper key={v.id} radius="lg" p={0} style={{ overflow: 'hidden', border: '1px solid rgba(255,255,255,0.07)' }}>
                        <Box style={{ height: 160, background: v.thumbnailColor }}>
                            <img src={v.image} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                onError={(e) => { e.target.style.display = 'none'; }} />
                        </Box>
                        <Stack gap={4} p="md">
                            <Text ff="var(--font-display)" fz={22} c="white">{v.make} {v.model}</Text>
                            <Text fz={12} c="dimmed">{v.variant} · {v.year}</Text>
                            <Button size="xs" variant="outline" color="brand" mt={4}
                                leftSection={<BookOpen size={12} />}
                                onClick={() => navigate(`/passport/${v.id}`)}>
                                View Passport
                            </Button>
                        </Stack>
                    </Paper>
                ))}
            </SimpleGrid>

            {/* Comparison table */}
            <Paper radius="lg" mb="xl" style={{ overflow: 'hidden' }}>
                <Table striped highlightOnHover>
                    <Table.Thead>
                        <Table.Tr>
                            <Table.Th style={{ width: '30%' }}>Spec</Table.Th>
                            <Table.Th>{v1.make} {v1.model}</Table.Th>
                            <Table.Th>{v2.make} {v2.model}</Table.Th>
                        </Table.Tr>
                    </Table.Thead>
                    <Table.Tbody>
                        {rows.map((row, i) => {
                            const winner = row.key ? getWinner(row.key, v1, v2) : 'tie';
                            const acc1 = row.accidents ? getAccidentCount(v1) : null;
                            const acc2 = row.accidents ? getAccidentCount(v2) : null;
                            return (
                                <Table.Tr key={i}>
                                    <Table.Td><Text fz={12} c="dimmed" tt="uppercase" lts="0.05em">{row.label}</Text></Table.Td>
                                    <Table.Td>
                                        <Group gap={6}>
                                            {row.accidents
                                                ? acc1 === 0
                                                    ? <><CheckCircle2 size={14} color="#00C875" /><Text fz={13} c="green.4">Clean</Text></>
                                                    : <><XCircle size={14} color="#FF4545" /><Text fz={13} c="red.4">{acc1} Accident(s)</Text></>
                                                : <Text fz={13} fw={winner === 'left' ? 700 : 400} c={winner === 'left' ? 'brand.4' : 'white'}>{row.fmt(v1)}</Text>}
                                            {winner === 'left' && !row.accidents && <Check size={12} color="#00C875" />}
                                        </Group>
                                    </Table.Td>
                                    <Table.Td>
                                        <Group gap={6}>
                                            {row.accidents
                                                ? acc2 === 0
                                                    ? <><CheckCircle2 size={14} color="#00C875" /><Text fz={13} c="green.4">Clean</Text></>
                                                    : <><XCircle size={14} color="#FF4545" /><Text fz={13} c="red.4">{acc2} Accident(s)</Text></>
                                                : <Text fz={13} fw={winner === 'right' ? 700 : 400} c={winner === 'right' ? 'brand.4' : 'white'}>{row.fmt(v2)}</Text>}
                                            {winner === 'right' && !row.accidents && <Check size={12} color="#00C875" />}
                                        </Group>
                                    </Table.Td>
                                </Table.Tr>
                            );
                        })}
                    </Table.Tbody>
                </Table>
            </Paper>

            {/* Trust Badges */}
            <Text ff="var(--font-display)" fz={28} c="white" mb="md">Trust Badges</Text>
            <Paper radius="lg" p="md" mb="xl">
                <Stack gap="sm">
                    {badgeKeys.map((key) => (
                        <Group key={key} justify="space-between" py={6} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                            <Group gap={6}>
                                {v1.badges?.[key]
                                    ? <CheckCircle2 size={16} color="#00C875" />
                                    : <XCircle size={16} color="#FF4545" />}
                                <Text fz={13} c={v1.badges?.[key] ? 'green.4' : 'dimmed'}>{badgeLabels[key]}</Text>
                            </Group>
                            <Badge variant="dot" color="gray" size="sm">{badgeLabels[key]}</Badge>
                            <Group gap={6}>
                                <Text fz={13} c={v2.badges?.[key] ? 'green.4' : 'dimmed'}>{badgeLabels[key]}</Text>
                                {v2.badges?.[key]
                                    ? <CheckCircle2 size={16} color="#00C875" />
                                    : <XCircle size={16} color="#FF4545" />}
                            </Group>
                        </Group>
                    ))}
                </Stack>
            </Paper>

            {/* Depreciation Chart */}
            <Text ff="var(--font-display)" fz={28} c="white" mb="md">Depreciation Comparison</Text>
            <Paper radius="lg" p="xl" mb="xl">
                <LineChart
                    h={260}
                    data={depChartData}
                    dataKey="year"
                    series={[
                        { name: `${v1.make} ${v1.model}`, color: '#4A9EFF' },
                        { name: `${v2.make} ${v2.model}`, color: '#F5C842' },
                    ]}
                    curveType="monotone"
                    gridAxis="xy"
                    tooltipProps={{
                        content: ({ payload }) => payload?.[0] ? (
                            <Paper p="xs" radius="md" style={{ background: '#25262b', border: '1px solid rgba(255,255,255,0.1)' }}>
                                {payload.map((p) => (
                                    <Text key={p.name} fz={12} c={p.color}>{p.name}: LKR {Number(p.value).toLocaleString()}</Text>
                                ))}
                            </Paper>
                        ) : null,
                    }}
                />
            </Paper>
        </Container>
    );
}

import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    Box, Group, Stack, Text, TextInput, Select, Button, Badge,
    SimpleGrid, Paper, ActionIcon, Tooltip, Divider, Container,
} from '@mantine/core';
import {
    Search, Repeat2, ScanSearch, Factory, BadgeCheck,
    Flag, Check, GitCompare, BookOpen, ArrowUpDown,
    Wrench, User, ShieldCheck, Gauge
} from 'lucide-react';
import { useAppStore } from '../../store/useAppStore';
import { useVehicleStore } from '../../store/useVehicleStore';
import { GRADE_COLORS } from '../../data/phaseColors';
import { formatLKR, formatKm } from '../../utils/formatters';
import useCountUp from '../../hooks/useCountUp';
import useIntersectionObserver from '../../hooks/useIntersectionObserver';
import '../../styles/Gallery.css';

export default function Gallery() {
    const [search, setSearch] = useState('');
    const [fuelFilter, setFuelFilter] = useState(null);
    const [gradeFilter, setGradeFilter] = useState(null);
    const [sortBy, setSortBy] = useState(null);
    const navigate = useNavigate();

    const compareList = useAppStore((s) => s.compareList);
    const addToCompare = useAppStore((s) => s.addToCompare);
    const removeFromCompare = useAppStore((s) => s.removeFromCompare);
    const allVehicles = useVehicleStore((s) => s.vehicles);

    const filtered = useMemo(() => {
        let results = allVehicles.filter((v) => {
            const q = search.toLowerCase();
            const matchQ = !q || `${v.make} ${v.model} ${v.variant}`.toLowerCase().includes(q);
            const matchFuel = !fuelFilter || v.fuelType.toLowerCase().includes(fuelFilter.toLowerCase());
            const matchGrade = !gradeFilter || v.condition_grade === Number(gradeFilter);
            return matchQ && matchFuel && matchGrade;
        });
        if (sortBy === 'price_asc') results.sort((a, b) => a.market_value_lkr - b.market_value_lkr);
        if (sortBy === 'price_desc') results.sort((a, b) => b.market_value_lkr - a.market_value_lkr);
        if (sortBy === 'year_desc') results.sort((a, b) => b.year - a.year);
        if (sortBy === 'year_asc') results.sort((a, b) => a.year - b.year);
        if (sortBy === 'grade_desc') results.sort((a, b) => b.condition_grade - a.condition_grade);
        return results;
    }, [search, fuelFilter, gradeFilter, sortBy, allVehicles]);

    const handleCompareToggle = (id) => {
        if (compareList.includes(id)) removeFromCompare(id);
        else addToCompare(id);
    };

    return (
        <div className="page" id="page-gallery">
            {/* ── Hero ── */}
            <section className="gallery-hero" style={{ position: 'relative', overflow: 'hidden' }}>
                <video
                    src="/bgvideo.mp4"
                    autoPlay loop muted playsInline
                    style={{
                        position: 'absolute',
                        top: '50%', left: '50%', width: '100%', height: '100%',
                        objectFit: 'cover', transform: 'translate(-50%, -50%)',
                        zIndex: 0, opacity: 0.35, pointerEvents: 'none'
                    }}
                />
                <div className="hero-grid-bg" style={{ zIndex: 1 }} />
                <div className="hero-glow-orb hero-orb-1" style={{ zIndex: 1 }} />
                <div className="hero-glow-orb hero-orb-2" style={{ zIndex: 1 }} />
                <div className="hero-content" style={{ zIndex: 2 }}>
                    <h1 className="hero-title">
                        Transparent Vehicle<br />
                        <span className="hero-title-accent">History &amp; Trust</span>
                    </h1>
                    <Box className="hero-description" visibleFrom="sm">
                        Every vehicle tells a story. AutoGenesis Passport verifies, documents,
                        and presents the complete lifecycle — from factory floor to your driveway.
                    </Box>
                    <Group gap="sm" mt="lg">
                        <Button
                            size="md" color="brand" radius="xl" fw={700}
                            onClick={() => document.getElementById('fleet-section')?.scrollIntoView({ behavior: 'smooth' })}
                        >
                            Explore Fleet
                        </Button>
                        <Button
                            size="md" variant="outline" color="gray" radius="xl" fw={600}
                            onClick={() => navigate('/compare')}
                        >
                            Compare Vehicles
                        </Button>
                    </Group>
                </div>
            </section>

            {/* ── Stats bar ── */}
            <HeroStats />

            {/* ── Fleet Section ── */}
            <section id="fleet-section" className="fleet-section">
                <Container size="xl">
                    <Stack gap={0} mb="lg">
                        <Text ff="var(--font-display)" fz={42} lts="0.04em" c="white">Explore Our Fleet</Text>
                        <Text fz={16} c="rgba(255,255,255,0.7)">Each vehicle comes with a verified digital passport</Text>
                    </Stack>
                </Container>

                {/* ── Filter Controls (all Mantine) ── */}
                <Container size="xl">
                    <Group gap="sm" mb="xl" wrap="wrap" align="flex-end">
                        <TextInput
                            placeholder="Search make, model, variant..."
                            leftSection={<Search size={15} />}
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            style={{ flex: 1, minWidth: 220 }}
                            radius="md"
                            styles={{ input: { height: 40 } }}
                        />
                        <Select
                            placeholder="All Fuel Types"
                            data={[
                                { value: 'hybrid', label: 'Hybrid' },
                                { value: 'electric', label: 'Electric' },
                                { value: 'plug-in', label: 'Plug-in Hybrid' },
                                { value: 'petrol', label: 'Petrol' },
                                { value: 'diesel', label: 'Diesel' },
                            ]}
                            value={fuelFilter}
                            onChange={setFuelFilter}
                            clearable
                            radius="md"
                            w={160}
                        />
                        <Select
                            placeholder="All Grades"
                            data={[
                                { value: '5', label: 'Grade 5 — Excellent' },
                                { value: '4', label: 'Grade 4 — Good' },
                                { value: '3', label: 'Grade 3 — Fair' },
                                { value: '2', label: 'Grade 2 — Below Avg' },
                                { value: '1', label: 'Grade 1 — Poor' },
                            ]}
                            value={gradeFilter}
                            onChange={setGradeFilter}
                            clearable
                            radius="md"
                            w={180}
                        />
                        <Select
                            placeholder="Sort by"
                            leftSection={<ArrowUpDown size={13} />}
                            data={[
                                { value: 'year_desc', label: 'Newest First' },
                                { value: 'year_asc', label: 'Oldest First' },
                                { value: 'price_asc', label: 'Lowest Price' },
                                { value: 'price_desc', label: 'Highest Price' },
                                { value: 'grade_desc', label: 'Best Grade' },
                            ]}
                            value={sortBy}
                            onChange={setSortBy}
                            clearable
                            radius="md"
                            w={160}
                        />
                        <Text fz={13} c="dimmed" style={{ whiteSpace: 'nowrap' }}>
                            {filtered.length} vehicle{filtered.length !== 1 ? 's' : ''}
                        </Text>
                    </Group>
                </Container>

                {/* ── Vehicle Grid ── */}
                <Container size="xl">
                    {filtered.length === 0 ? (
                        <Paper p="xl" ta="center" radius="lg" style={{ border: '1px dashed rgba(255,255,255,0.1)' }}>
                            <Text fz={16} fw={600} c="white" mb={4}>No Vehicles Found</Text>
                            <Text fz={13} c="dimmed">Try adjusting your search or filters</Text>
                        </Paper>
                    ) : (
                        <SimpleGrid cols={{ base: 1, sm: 2, md: 3, lg: 3 }} spacing="lg">
                            {filtered.map((v, i) => (
                                <VehicleCard
                                    key={v.id}
                                    vehicle={v}
                                    index={i}
                                    isComparing={compareList.includes(v.id)}
                                    onCompareToggle={handleCompareToggle}
                                    onViewPassport={() => navigate(`/passport/${v.id}`)}
                                    onSwap={() => navigate(`/swap/${v.id}`)}
                                />
                            ))}
                        </SimpleGrid>
                    )}
                </Container>
            </section>
        </div>
    );
}

/* ── Hero Stats ── */
function HeroStats() {
    const [ref, isVisible] = useIntersectionObserver();
    const vehicles = useCountUp(5, 800, (n) => n, isVisible);
    const records = useCountUp(47, 1200, (n) => n, isVisible);
    const trust = useCountUp(3200, 1600, (n) => n.toLocaleString(), isVisible);

    return (
        <div className="hero-stats" ref={ref}>
            <div className="hero-stat">
                <span className="hero-stat-number">{vehicles}</span>
                <span className="hero-stat-label">Certified Vehicles</span>
            </div>
            <div className="hero-stat-divider" />
            <div className="hero-stat">
                <span className="hero-stat-number">{records}</span>
                <span className="hero-stat-label">Verified Records</span>
            </div>
            <div className="hero-stat-divider" />
            <div className="hero-stat">
                <span className="hero-stat-number">{trust}+</span>
                <span className="hero-stat-label">Trusted Owners</span>
            </div>
            <div className="hero-stat-divider" />
            <div className="hero-stat">
                <span className="hero-stat-number">100%</span>
                <span className="hero-stat-label">Verified Sources</span>
            </div>
        </div>
    );
}

/* ── Vehicle Card ── */
function VehicleCard({ vehicle: v, index, isComparing, onCompareToggle, onViewPassport, onSwap }) {
    const [imgRef, isVisible] = useIntersectionObserver();
    const gradeColor = GRADE_COLORS[v.condition_grade] || '#999';
    const badgeKeys = ['on_time_service', 'one_owner', 'no_accident', 'untampered_mileage'];
    const badgeLabels = ['On-Time Service', 'One Owner', 'No Accident', 'Mileage Verified'];
    const earnedCount = badgeKeys.filter((k) => v.badges?.[k]).length;

    return (
        <Paper
            ref={imgRef}
            radius="lg"
            className={`vehicle-card ${isComparing ? 'selected' : ''} ${isVisible ? 'visible' : ''}`}
            style={{
                transitionDelay: `${index * 60}ms`,
                overflow: 'hidden',
                background: 'rgba(17,24,39,0.7)',
                backdropFilter: 'blur(12px)',
                WebkitBackdropFilter: 'blur(12px)',
                border: isComparing ? '1px solid rgba(59,130,246,0.5)' : '1px solid rgba(255,255,255,0.07)',
            }}
        >
            {/* Image */}
            <Box
                className="card-image-wrap"
                style={{ backgroundColor: v.thumbnailColor, position: 'relative' }}
            >
                <img
                    src={v.image} alt={`${v.make} ${v.model}`} loading="lazy"
                    onError={(e) => { e.target.style.display = 'none'; }}
                />
                {/* Grade badge */}
                <Box
                    style={{
                        position: 'absolute', top: 10, right: 10,
                        background: gradeColor, color: v.condition_grade <= 1 ? '#fff' : '#000',
                        padding: '2px 9px', borderRadius: 99,
                        fontSize: 12, fontWeight: 700, fontFamily: 'var(--font-body)',
                    }}
                >
                    {v.condition_grade}★
                </Box>
                {/* Compare check */}
                <Tooltip
                    label={isComparing ? 'Remove from compare' : 'Add to compare'}
                    position="top"
                    withArrow
                >
                    <Box
                        className={`card-compare-check ${isComparing ? 'checked' : ''}`}
                        onClick={(e) => { e.stopPropagation(); onCompareToggle(v.id); }}
                        role="checkbox"
                        aria-checked={isComparing}
                        aria-label={`Compare ${v.make} ${v.model}`}
                        tabIndex={0}
                        onKeyDown={(e) => e.key === 'Enter' && onCompareToggle(v.id)}
                    >
                        {isComparing && <Check size={12} strokeWidth={3} />}
                    </Box>
                </Tooltip>
            </Box>

            {/* Body */}
            <Stack gap={10} p="md">
                <Box>
                    <Text ff="var(--font-display)" fz={20} lts="0.03em" c="white" lh={1.1}>
                        {v.make} {v.model}
                    </Text>
                    <Text fz={12} c="dimmed" mt={2}>{v.variant} · {v.year}</Text>
                </Box>

                {/* Stats row */}
                <Group gap={0} grow style={{ borderTop: '1px solid rgba(255,255,255,0.06)', paddingTop: 8 }}>
                    {[
                        { label: 'Age', value: `${v.age}y` },
                        { label: 'Mileage', value: formatKm(v.mileage) },
                        { label: 'Grade', value: `${v.condition_grade}/5`, color: gradeColor },
                    ].map((s) => (
                        <Box key={s.label} ta="center">
                            <Text fz={13} fw={700} c={s.color || 'white'}>{s.value}</Text>
                            <Text fz={10} c="dimmed" tt="uppercase" lts="0.05em">{s.label}</Text>
                        </Box>
                    ))}
                </Group>

                {/* Price */}
                <Text fw={700} fz={16} c="brand.4">{formatLKR(v.market_value_lkr)}</Text>

                {/* Trust Badges - explicit icons */}
                <Group gap={6}>
                    {v.badges?.on_time_service && (
                        <Tooltip label="On-Time Service" withArrow position="top">
                            <Box style={{ color: '#3b82f6' }}><Wrench size={14} /></Box>
                        </Tooltip>
                    )}
                    {v.badges?.one_owner && (
                        <Tooltip label="One Owner" withArrow position="top">
                            <Box style={{ color: '#3b82f6' }}><User size={14} /></Box>
                        </Tooltip>
                    )}
                    {v.badges?.no_accident && (
                        <Tooltip label="No Accident" withArrow position="top">
                            <Box style={{ color: '#3b82f6' }}><ShieldCheck size={14} /></Box>
                        </Tooltip>
                    )}
                    {v.badges?.untampered_mileage && (
                        <Tooltip label="Mileage Verified" withArrow position="top">
                            <Box style={{ color: '#3b82f6' }}><Gauge size={14} /></Box>
                        </Tooltip>
                    )}
                    <Text fz={10} c="dimmed" ml="auto">{earnedCount}/4 verified</Text>
                </Group>

                {/* Actions */}
                <Group gap="xs" grow>
                    <Button
                        size="xs" color="brand" radius="md" fw={700}
                        onClick={onViewPassport}
                        leftSection={<BookOpen size={13} />}
                    >
                        View Passport
                    </Button>
                    <Button
                        size="xs" variant="outline" color="gray" radius="md" fw={600}
                        onClick={onSwap}
                        leftSection={<Repeat2 size={13} />}
                    >
                        Swap
                    </Button>
                </Group>
            </Stack>
        </Paper>
    );
}
